# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return f"Deposited {amount}. Current balance is {self.balance}"
        else:
            return "Invalid deposit amount"

    def withdraw(self, amount):
        if amount > 0 and amount <= self.balance:
            self.balance -= amount
            return f"Withdrew {amount}. Current balance is {self.balance}"
        elif amount == 0:
            return "Invalid withdrawal amount"
        else:
            return "Insufficient funds"

def process_transactions(transactions):
    account = Account()
    
    for transaction in transactions:
        if transaction['type'] == 'deposit':
            print(account.deposit(transaction['amount']))
        elif transaction['type'] == 'withdrawal':
            print(account.withdraw(transaction['amount']))

# Example usage
transactions = [
    {'type': 'deposit', 'amount': 100},
    {'type': 'withdrawal', 'amount': 50},
    {'type': 'deposit', 'amount': 200}
]

process_transactions(transactions)